import { Box, Group, Stack, Text, Title } from '@mantine/core'
import { useMediaQuery } from '@mantine/hooks'
import { useState } from 'react'

import { useAppConfig } from '@entities/app-config-store'

type PlanType = 'basic' | 'pro'

const planConfig = {
    basic: {
        youGradient: 'linear-gradient(90deg, #3162aa 0%, #4f94fd 50%, #1e4e97 100%)',
        numberBackground: '#6298E8',
        buttonGradient: 'linear-gradient(135deg, #3162aa 0%, #4f94fd 50%, #1e4e97 100%)',
        buttonBorder: '1.5px solid #6298E8'
    },
    pro: {
        youGradient: 'linear-gradient(90deg, #6831aa 0%, #b14ffd 50%, #7f1e97 100%)',
        numberBackground: '#9A62E8',
        buttonGradient: 'linear-gradient(90deg, #6831aa 0%, #b14ffd 50%, #7f1e97 100%)',
        buttonBorder: '1.5px solid #9A62E8'
    }
}

interface IDevice {
    addedAt: string
    deviceNumber?: number
    isCurrentDevice?: boolean
    model: string
    platform: string
}

interface IProps {
    devices?: IDevice[]
    onAddDevice?: () => void
}

