const getPlatformIcon = (platform: string) => {
    const p = platform.toLowerCase()
    if (p.includes('ios') || p.includes('mac')) return <AppleIcon />
    return <AndroidIcon />
}

interface IBadgeProps {
    children: React.ReactNode
    isYou?: boolean
    numberBackground: string
    youGradient: string
}

const Badge = ({ children, isYou, youGradient, numberBackground }: IBadgeProps) => {
    const isMobile = useMediaQuery('(max-width: 768px)')

    return (
        <Box
            style={{
                background: isYou ? youGradient : numberBackground,
                borderRadius: 60,
                minWidth: isMobile ? 36 : 59,
                height: isMobile ? 36 : 59,
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                padding: '0 5px',
                flexShrink: 0
            }}
        >
            <Text fw={700} size={isMobile ? 'xs' : 'md'} style={{ color: 'white' }}>
                {children}
            </Text>
        </Box>
    )
}

const DEFAULT_DEVICES: IDevice[] = [
    { model: '67304289PT', platform: 'iOS 26', addedAt: '2025-12-31 11:14', isCurrentDevice: true },
    { model: '22101316UG', platform: 'Android 14', addedAt: '2026-02-31 14:03', deviceNumber: 2 }
]

export const DevicesWidget = ({ devices = DEFAULT_DEVICES, onAddDevice }: IProps) => {
    const isMobile = useMediaQuery('(max-width: 768px)')
    const [btnHovered, setBtnHovered] = useState(false)
    const config = useAppConfig() as { userType?: PlanType }
    const planType: PlanType = config.userType || 'basic'
    const { youGradient, numberBackground, buttonGradient, buttonBorder } = planConfig[planType]

    const iconSize = { borderRadius: 60, padding: 10 }

    return (
        <Box
            style={{
                background: 'rgb(28, 32, 41)',
                border: '1px solid #2D3238',
                borderRadius: 16,
                padding: '20px'
            }}
        >
            <Title
                c="white"
                fw={700}
                mb="md"
                order={isMobile ? 3 : 2}
                style={{ fontSize: isMobile ? 24 : 32 }}
            >
                Подключенные устройства
            </Title>

            <Stack gap="md" mb="md">
                {devices.map((device, index) => (
                    <Group justify="space-between" key={index} wrap="nowrap">
                        <Group gap="sm" wrap="nowrap">
                            <Box
                                style={{
                                    ...iconSize,
                                    display: 'flex',
                                    alignItems: 'center',
                                    justifyContent: 'center',
                                    flexShrink: 0
                                }}
                            >
                                {getPlatformIcon(device.platform)}
                            </Box>
                            <Stack gap={2}>
                                <Text
                                    c="white"
                                    style={{ fontSize: isMobile ? 12 : 14, fontWeight: 500 }}
                                >
                                    Модель: {device.model}
                                </Text>
                                <Text
                                    c="white"
                                    style={{ fontSize: isMobile ? 12 : 14, fontWeight: 500 }}
                                >
                                    Платформа: {device.platform}
                                </Text>
                                <Text
                                    c="white"
                                    style={{ fontSize: isMobile ? 12 : 14, fontWeight: 500 }}
                                >
                                    Добавлено: {device.addedAt}
                                </Text>
                            </Stack>
                        </Group>

                        {device.isCurrentDevice && (
                            <Badge
                                isYou
                                numberBackground={numberBackground}
                                youGradient={youGradient}
                            >
                                Вы
                            </Badge>
                        )}
                        {device.deviceNumber && (
                            <Badge numberBackground={numberBackground} youGradient={youGradient}>
                                {device.deviceNumber}
                            </Badge>
                        )}
                    </Group>
                ))}
            </Stack>

            <Box
                onClick={onAddDevice}
                onMouseEnter={() => setBtnHovered(true)}
                onMouseLeave={() => setBtnHovered(false)}
                style={{
                    background: buttonGradient,
                    border: buttonBorder,
                    borderRadius: 12,
                    padding: '10px 20px',
                    cursor: 'pointer',
                    width: '100%',
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                    opacity: btnHovered ? 0.7 : 1,
                    transition: 'opacity 0.15s ease',
                    boxSizing: 'border-box'
                }}
            >
                <Text c="white" fw={700} style={{ fontSize: isMobile ? 14 : 20 }}>
                    Добавить устройство
                </Text>
            </Box>
        </Box>
    )
}
